import React, { useEffect } from 'react';
import { Pie, Bar, Line, Scatter } from 'react-chartjs-2';
import './Reports.css';

import {
  Chart as ChartJS,
  ArcElement,
  BarElement,
  LineElement,
  PointElement,
  CategoryScale,
  LinearScale,
  Title,
  Tooltip,
  Legend,
} from 'chart.js';

ChartJS.register(
  ArcElement,
  BarElement,
  LineElement,
  PointElement,
  CategoryScale,
  LinearScale,
  Title,
  Tooltip,
  Legend
);

const chartStyle = {
  maxWidth: 500,
  maxHeight: 350,
  margin: '0 auto',
};

const Reports = () => {
  const defaultData = {
    labels: ['Sample A', 'Sample B', 'Sample C'],
    datasets: [
      {
        label: 'Sample Data',
        data: [10, 20, 30],
        backgroundColor: ['#FF6384', '#36A2EB', '#FFCE56'],
      },
    ],
  };

  const defaultOptions = {
    responsive: true,
    plugins: {
      legend: {
        position: 'top',
      },
      title: {
        display: true,
        text: 'Default Chart',
      },
    },
    maintainAspectRatio: false,
  };

  useEffect(() => {
    console.log('Default Data:', defaultData);
    console.log('Default Options:', defaultOptions);
  }, [defaultData, defaultOptions]);

  return (
    <div className="reports-container">
      <h1>Reports Dashboard</h1>

      <div className="report-section">
        <h2>1️⃣ Category Distribution</h2>
        <div style={chartStyle}>
          <Pie data={defaultData} options={defaultOptions} height={350} width={500} />
        </div>
      </div>

      <div className="report-section">
        <h2>2️⃣ Brand Popularity</h2>
        <div style={chartStyle}>
          <Bar data={defaultData} options={defaultOptions} height={350} width={500} />
        </div>
      </div>

      <div className="report-section">
        <h2>3️⃣ Price Range Analysis</h2>
        <div style={chartStyle}>
          <Bar data={defaultData} options={defaultOptions} height={350} width={500} />
        </div>
      </div>

      <div className="report-section">
        <h2>4️⃣ Top Selling Products</h2>
        <div style={chartStyle}>
          <Bar
            data={defaultData}
            options={{
              ...defaultOptions,
              indexAxis: 'y',
              title: {
                display: true,
                text: 'Top Selling Products',
              },
            }}
            height={350}
            width={500}
          />
        </div>
      </div>

      <div className="report-section">
        <h2>5️⃣ Rating Distribution</h2>
        <div style={chartStyle}>
          <Bar data={defaultData} options={defaultOptions} height={350} width={500} />
        </div>
      </div>

      <div className="report-section">
        <h2>6️⃣ Stock vs Sales Analysis</h2>
        <div style={chartStyle}>
          <Scatter data={defaultData} options={defaultOptions} height={350} width={500} />
        </div>
      </div>

      <div className="report-section">
        <h2>7️⃣ Monthly Revenue Trend</h2>
        <div style={chartStyle}>
          <Line data={defaultData} options={defaultOptions} height={350} width={500} />
        </div>
      </div>

      <div className="report-section">
        <h2>8️⃣ ML Demand Prediction</h2>
        <div style={chartStyle}>
          <Line data={defaultData} options={defaultOptions} height={350} width={500} />
        </div>
      </div>
    </div>
  );
};

export default Reports;
